import { LitElement, TemplateResult, css, html, nothing } from 'lit';

import { HomeAssistant } from './ha_type_stubs';
import {
    CodeDisplayMode,
    ConfigEntryJSONFragment,
    LockCodeManagerConfigEntryDataResponse,
    LockCodesCardConfig,
    LockInfo
} from './types';

const CODE_DISPLAY_OPTIONS: Array<{ label: string; value: CodeDisplayMode }> = [
    { label: 'Masked with Reveal', value: 'masked_with_reveal' },
    { label: 'Always Masked', value: 'masked' },
    { label: 'Always Visible', value: 'unmasked' }
];

class LockCodesCardEditor extends LitElement {
    static styles = css`
        .editor-row {
            margin-bottom: 16px;
        }

        ha-entity-picker,
        ha-textfield,
        ha-select {
            display: block;
            width: 100%;
        }

        .no-locks-warning {
            color: var(--warning-color);
            padding: 8px;
        }
    `;

    private _hass?: HomeAssistant;
    private _config?: LockCodesCardConfig;
    private _locks: LockInfo[] = [];
    private _loading = true;

    set hass(hass: HomeAssistant) {
        const hassChanged = this._hass !== hass;
        this._hass = hass;
        if (hassChanged) {
            void this._fetchLocks();
        }
    }

    setConfig(config: LockCodesCardConfig): void {
        this._config = config;
    }

    protected render(): TemplateResult {
        if (!this._hass || !this._config) {
            return html``;
        }

        const lockEntityIds = this._locks.map((l) => l.entity_id);

        return html`
            <div class="editor-row">
                ${this._loading
                    ? html`<span>Loading locks...</span>`
                    : this._locks.length === 0
                      ? html`<div class="no-locks-warning">
                            No locks are currently managed by Lock Code Manager.
                        </div>`
                      : nothing}
                <ha-entity-picker
                    .hass=${this._hass}
                    .value=${this._config.lock_entity_id}
                    .includeEntities=${lockEntityIds}
                    .label=${'Lock'}
                    .required=${true}
                    @value-changed=${this._lockChanged}
                ></ha-entity-picker>
            </div>

            <div class="editor-row">
                <ha-textfield
                    .label=${'Title (optional)'}
                    .value=${this._config.title ?? ''}
                    @input=${this._titleChanged}
                ></ha-textfield>
            </div>

            <div class="editor-row">
                <ha-select
                    .label=${'Code Display'}
                    .value=${this._config.code_display ?? 'unmasked'}
                    @selected=${this._displayModeChanged}
                    @closed=${this._stopPropagation}
                    fixedMenuPosition
                    naturalMenuWidth
                >
                    ${CODE_DISPLAY_OPTIONS.map(
                        (opt) =>
                            html`<mwc-list-item .value=${opt.value}>${opt.label}</mwc-list-item>`
                    )}
                </ha-select>
            </div>
        `;
    }

    private async _fetchLocks(): Promise<void> {
        if (!this._hass) {
            return;
        }
        this._loading = true;
        try {
            // First get all LCM config entries
            const configEntries = await this._hass.callWS<ConfigEntryJSONFragment[]>({
                domain: 'lock_code_manager',
                type: 'config_entries/get'
            });

            // Fetch locks from each config entry in parallel and combine (dedupe by entity_id)
            const hass = this._hass;
            const results = await Promise.allSettled(
                configEntries.map((entry) =>
                    hass.callWS<LockCodeManagerConfigEntryDataResponse>({
                        config_entry_id: entry.entry_id,
                        type: 'lock_code_manager/get_config_entry_data'
                    })
                )
            );

            const lockMap = new Map<string, LockInfo>();
            for (const result of results) {
                if (result.status === 'fulfilled') {
                    for (const lock of result.value.locks) {
                        lockMap.set(lock.entity_id, lock);
                    }
                }
                // Skip rejected promises (e.g., config entries not loaded)
            }
            this._locks = Array.from(lockMap.values());
        } catch {
            this._locks = [];
        }
        this._loading = false;
        this.requestUpdate();
    }

    private _lockChanged(ev: CustomEvent): void {
        if (!this._config) {
            return;
        }
        const { value } = ev.detail;
        if (value === this._config.lock_entity_id) {
            return;
        }
        this._config = { ...this._config, lock_entity_id: value };
        this._dispatchConfig();
    }

    private _titleChanged(ev: Event): void {
        if (!this._config) {
            return;
        }
        const target = ev.target as HTMLInputElement;
        const value = target.value || undefined;
        if (value === this._config.title) {
            return;
        }
        this._config = { ...this._config, title: value };
        this._dispatchConfig();
    }

    private _displayModeChanged(ev: CustomEvent): void {
        if (!this._config) {
            return;
        }
        const target = ev.target as HTMLSelectElement;
        const value = target.value as CodeDisplayMode;
        if (value === this._config.code_display) {
            return;
        }
        this._config = { ...this._config, code_display: value };
        this._dispatchConfig();
    }

    private _stopPropagation(ev: Event): void {
        ev.stopPropagation();
    }

    private _dispatchConfig(): void {
        this.dispatchEvent(
            new CustomEvent('config-changed', {
                bubbles: true,
                composed: true,
                detail: { config: this._config }
            })
        );
    }
}

customElements.define('lcm-lock-codes-editor', LockCodesCardEditor);

import { LitElement, TemplateResult, css, html, nothing } from 'lit';

import { HomeAssistant } from './ha_type_stubs';
import {
    CodeDisplayMode,
    ConfigEntryJSONFragment,
    GetConfigEntriesResponse,
    LockCodeManagerSlotCardConfig
} from './types';

const CODE_DISPLAY_OPTIONS: Array<{ label: string; value: CodeDisplayMode }> = [
    { label: 'Masked with Reveal', value: 'masked_with_reveal' },
    { label: 'Always Masked', value: 'masked' },
    { label: 'Always Visible', value: 'unmasked' }
];

class LcmSlotCardEditor extends LitElement {
    static styles = css`
        .editor-row {
            margin-bottom: 16px;
        }

        ha-textfield,
        ha-select {
            display: block;
            width: 100%;
        }

        .no-entries-warning {
            color: var(--warning-color);
            padding: 8px;
        }

        .checkbox-row {
            align-items: center;
            display: flex;
            gap: 8px;
            margin-bottom: 8px;
        }

        .checkbox-row label {
            cursor: pointer;
        }

        .section-label {
            color: var(--secondary-text-color);
            font-size: 12px;
            font-weight: 500;
            letter-spacing: 0.05em;
            margin-bottom: 8px;
            margin-top: 16px;
            text-transform: uppercase;
        }
    `;

    private _hass?: HomeAssistant;
    private _config?: LockCodeManagerSlotCardConfig;
    private _configEntries: ConfigEntryJSONFragment[] = [];
    private _loading = true;

    set hass(hass: HomeAssistant) {
        const hassChanged = this._hass !== hass;
        this._hass = hass;
        if (hassChanged) {
            void this._fetchConfigEntries();
        }
    }

    setConfig(config: LockCodeManagerSlotCardConfig): void {
        this._config = config;
    }

    protected render(): TemplateResult {
        if (!this._hass || !this._config) {
            return html``;
        }

        return html`
            <div class="editor-row">
