            const msg = subscribeMessage.mock.calls[0][1];
            expect(msg).toMatchObject({
                config_entry_title: 'My Lock Manager',
                slot: 2,
                type: 'lock_code_manager/subscribe_code_slot'
            });
            expect(msg.config_entry_id).toBeUndefined();
        });
    });

