            card2.hass = hass;
            container.appendChild(card2);
            await flush();

            capturedCallback!(
                makeSlotCardData({
                    locks: [
                        {
                            code: 'unknown',
                            entity_id: 'lock.test_1',
                            in_sync: true,
                            name: 'Masked Lock'
                        },
                        {
                            code: 'empty',
