static async generate(config: LockCodeManagerViewStrategyConfig, hass: HomeAssistant) {
    const { config_entry_id, config_entry_title } = config;

    if (hass.config.state === STATE_NOT_RUNNING) {
        return createStartingView();
    }

    const validation = validateViewStrategyConfig(config);
    if (!validation.valid) {
        return createErrorView(
            '## ERROR: Either `config_entry_title` or `config_entry_id` must ' +
                'be provided in the view config, but not both!'
        );
    }

    try {
        const { config_entry } = await hass.callWS<LockCodeManagerConfigEntryDataResponse>({
            config_entry_id,
            config_entry_title,
            type: 'lock_code_manager/get_config_entry_data'
        });

        // Map legacy options to new names (new options take precedence)
        const showCodeSensors =
            config.show_code_sensors ??
            config.include_code_slot_sensors ??
            DEFAULT_SHOW_CODE_SENSORS;
        const showLockSync =
            config.show_lock_sync ?? config.include_in_sync_sensors ?? DEFAULT_SHOW_LOCK_SYNC;
        const codeDisplay =
            config.code_display ?? config.code_data_view_code_display ?? DEFAULT_CODE_DISPLAY;

        // Support legacy show_all_codes_for_locks option for backwards compatibility
        const showLockCards =
            config.show_lock_cards ??
            config.show_all_codes_for_locks ??
            DEFAULT_SHOW_LOCK_CARDS;

        return generateView(hass, config_entry, {
            codeDisplay,
            collapsedSections: config.collapsed_sections,
            showCodeSensors,
            showConditions: config.show_conditions ?? DEFAULT_SHOW_CONDITIONS,
            showLockCards,
            showLockStatus: config.show_lock_status ?? DEFAULT_SHOW_LOCK_STATUS,
            showLockSync,
            useSlotCards: config.use_slot_cards ?? DEFAULT_USE_SLOT_CARDS
        });
    } catch {
        return createErrorView(
            formatConfigEntryNotFoundError(config_entry_id, config_entry_title)
        );
    }
}
