export async function generateView(
    hass: HomeAssistant,
    configEntry: ConfigEntryJSONFragment,
    options: GenerateViewOptions
): Promise<LovelaceViewConfig> {
    const {
        showCodeSensors: show_code_sensors,
        showLockSync: show_lock_sync,
        showLockCards: show_lock_cards,
        codeDisplay: code_display,
        useSlotCards: use_slot_cards,
        showConditions: show_conditions = true,
        showLockStatus: show_lock_status = true,
        collapsedSections: collapsed_sections
    } = options;
    const configEntryData = await hass.callWS<LockCodeManagerConfigEntryDataResponse>({
        config_entry_id: configEntry.entry_id,
        type: 'lock_code_manager/get_config_entry_data'
    });

    const slots = Object.keys(configEntryData.slots).map((slotNum) => parseInt(slotNum, 10));

    // Build badges - lock state badges only
    const badges: Array<string | object> = [];

    // Lock state badges - show each lock with its current state
    configEntryData.locks
        .sort((a, b) => a.entity_id.localeCompare(b.entity_id))
        .forEach((lock) => {
            badges.push({
                entity: lock.entity_id,
                show_name: true,
                type: 'entity'
            });
        });

    // Generate sections using section strategies
    const sections: LovelaceSectionConfig[] = slots.map((slotNum) => {
        return {
            strategy: {
                code_display,
                collapsed_sections,
                config_entry_id: configEntry.entry_id,
                show_code_sensors,
                show_conditions,
                show_lock_count: false,
                show_lock_status,
                show_lock_sync,
                slot: slotNum,
                type: 'custom:lock-code-manager-slot',
                use_slot_cards
            }
        };
    });

    if (show_lock_cards) {
        // Add lock codes sections using section strategy
        const sortedLocks = [...configEntryData.locks].sort((a, b) =>
            a.name.localeCompare(b.name, undefined, { sensitivity: 'base' })
        );
        sortedLocks.forEach((lock) => {
            sections.push({
                strategy: {
                    code_display,
                    lock_entity_id: lock.entity_id,
                    type: 'custom:lock-code-manager-lock'
                }
            });
        });
    }

    return {
        badges,
        panel: false,
        path: slugify(configEntry.title),
        sections,
        title: configEntry.title,
        type: 'sections'
    };
}
```

